const themeLabels = {
  system: "Auto",
  light: "Light",
  dark: "Dark"
};

const savedTheme = localStorage.getItem("customremote-theme") || "system";

function applyTheme(theme) {
  const normalizedTheme = ["system", "light", "dark"].includes(theme) ? theme : "system";
  if (normalizedTheme === "system") {
    document.documentElement.removeAttribute("data-theme");
  } else {
    document.documentElement.dataset.theme = normalizedTheme;
  }
  localStorage.setItem("customremote-theme", normalizedTheme);
  document.querySelectorAll("[data-theme-toggle]").forEach((button) => {
    button.dataset.themeMode = normalizedTheme;
    button.textContent = themeLabels[normalizedTheme];
    button.setAttribute("aria-label", `Appearance: ${themeLabels[normalizedTheme]}`);
  });
}

applyTheme(savedTheme);

document.querySelectorAll("[data-theme-toggle]").forEach((button) => {
  button.addEventListener("click", () => {
    const currentTheme = button.dataset.themeMode || "system";
    const nextTheme = currentTheme === "system" ? "dark" : currentTheme === "dark" ? "light" : "system";
    applyTheme(nextTheme);
  });
});

document.querySelectorAll("[data-toggle]").forEach((button) => {
  button.addEventListener("click", () => button.classList.toggle("on"));
});

document.querySelectorAll("[data-segmented]").forEach((group) => {
  group.addEventListener("click", (event) => {
    const button = event.target.closest("button");
    if (!button) return;
    group.querySelectorAll("button").forEach((item) => item.classList.remove("active"));
    button.classList.add("active");
  });
});

document.querySelectorAll("[data-remote-key]").forEach((button) => {
  button.addEventListener("click", () => {
    document.querySelectorAll("[data-remote-key]").forEach((item) => item.classList.remove("active"));
    button.classList.add("active");
    const output = document.querySelector("[data-key-output]");
    if (output) output.textContent = button.dataset.remoteKey;
    const captured = document.querySelector("[data-captured-input]");
    if (captured) captured.value = `Apple TV Remote · ${button.dataset.remoteKey}`;
  });
});

document.querySelectorAll("[data-filter]").forEach((button) => {
  button.addEventListener("click", () => {
    const filter = button.dataset.filter;
    document.querySelectorAll("[data-map-row]").forEach((row) => {
      row.hidden = filter !== "all" && row.dataset.mapRow !== filter;
    });
  });
});

document.querySelectorAll(".mapping-row").forEach((row) => {
  row.addEventListener("click", () => {
    document.querySelectorAll(".mapping-row").forEach((item) => item.classList.remove("selected"));
    row.classList.add("selected");
    const captured = document.querySelector("[data-captured-input]");
    if (captured && row.dataset.input) captured.value = row.dataset.input;
  });
});

